class Solution {
public:
    int maxLengthBetweenEqualCharacters(string s) {
        int countA = 0, countB = 0;
        int result = -1;
        for (int i = 0; i < s.length(); i++) {
            if (s[i] == 'a') {
                countA++;
            } else {
                countB++;
            }
            if (countA > countB) {
                result = max(result, countA - countB);
                countA = 0;
                countB = 0;
            }
        }
        return result;
    }
};
```

